// NFT example: mints and transfers an NFT

seiyaku NftDemo {
  fn owner_id() -> AccountId {
    let owner = account!("sorauﾛ1QG1ｼﾀ3vN7ﾋzﾄﾍcﾐLKDCAｲ5ｸｴjﾔﾘ2uﾄﾕmｷﾕﾙeJBJW7X2N7");
    return owner;
  }

  fn recipient_id() -> AccountId {
    let recipient = account!("sorauﾛ1NksﾂJZﾐLﾂｽjﾖrUphCSﾎ8Wﾉｽﾏﾁﾓr3ﾑLｾﾇﾋYqwﾌﾉFTMDQE");
    return recipient;
  }

  fn dragon_nft() -> NftId {
    let nft = nft_id!("dragon$wonderland");
    return nft;
  }

  kotoage fn create() permission(NftAuthority) {
    let owner = owner_id();
    let nft = dragon_nft();
    nft_mint_asset(nft, owner);
  }

  kotoage fn transfer() permission(NftAuthority) {
    let owner = owner_id();
    let recipient = recipient_id();
    let nft = dragon_nft();
    nft_transfer_asset(owner, nft, recipient);
  }
}
